# for və while ilə generatorlar
def even_numbers():
    n = 0
    while n < 6:
        yield n
        n += 2

gen = even_numbers()

# for dövrü
print('for dövrü ilə:')
for num in gen:
    print(num)

gen = even_numbers()  # Yenidən generator yarat
# while dövrü
print('while dövrü ilə:')
while True:
    try:
        print(next(gen))
    except StopIteration:
        break

// JavaScript kodu
function* numberGenerator() {
    yield 1;
    yield 2;
    yield 3;
}

const gen = numberGenerator();
console.log(gen.next().value);

# Səhvlərdən qaçınma
def safe_generator():
    for i in range(3):
        yield i

gen = safe_generator()
try:
    print(next(gen))
    print(next(gen))
    print(next(gen))
    print(next(gen))  # StopIteration
except StopIteration:
    print('Generator bitdi!')

# Layihədə istifadə
def fibonacci(n):
    a, b = 0, 1
    for _ in range(n):
        yield a
        a, b = b, a + b

fib = fibonacci(5)
for num in fib:
    print(num)

